def organizer_events(request):
    """ View to display organizer's events. """
    if not request.user.is_authenticated:
        return redirect('users:login')
    try:
        profile = request.user.profile
        is_organizer = profile.role == 'organizer'
    except UserProfile.DoesNotExist:
        is_organizer = False

    is_admin = request.user.is_staff

    if not is_organizer and not is_admin:
        messages.error(request, 'Accesso negato. Solo gli organizzatori e gli admin possono visualizzare questa pagina.')
        return redirect('events:event_list')

    # Admin vede tutti gli eventi, gli organizzatori vedono solo i loro
    if is_admin:
        events = Event.objects.all().order_by('-start_date')
    else:
        events = Event.objects.filter(organizer=request.user).order_by('-start_date')

    from django.utils import timezone
    for event in events:
        if event.deleted_at:
            event.can_restore = (timezone.now() - event.deleted_at).days < 3
        else:
            event.can_restore = False
    context = {'events': events, 'title': 'I miei eventi', 'is_admin': is_admin}
    return render(request, 'events/organizer_events.html', context)

def event_restore(request, pk):
    """ View to restore a deleted event. """
    if not request.user.is_authenticated:
        messages.error(request, 'È necessario essere loggati.')
        return redirect('users:login')
    event = get_object_or_404(Event, pk=pk, organizer=request.user)
    if event.deleted_at:
        from django.utils import timezone
        if (timezone.now() - event.deleted_at).days < 3:
            event.deleted_at = None
            event.save()
            messages.success(request, 'Evento ripristinato con successo!')
        else:
            messages.error(request, 'Non è possibile ripristinare eventi eliminati da più di 3 giorni.')
    else:
        messages.warning(request, 'L\'evento non è eliminato.')
    return redirect('events:organizer_events')

def admin_unregister_user(request, event_id, registration_id):
    """ View to unregister a user from an event (admin only). """
    if not request.user.is_authenticated or not request.user.is_staff:
        messages.error(request, 'Accesso negato. Solo gli admin possono eseguire questa azione.')
        return redirect('events:event_list')

    event = get_object_or_404(Event, pk=event_id)
    registration = get_object_or_404(EventRegistration, pk=registration_id, event=event)

    user_name = registration.user.username
    registration.delete()
    messages.success(request, f'Utente {user_name} discritto dall\'evento {event.title}.')
    return redirect('events:event_detail', pk=event_id)

{% extends 'base.html' %}

{% block title %}I Miei Eventi - Event Management System{% endblock %}

{% block content %}
<div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 2rem;">
    <h2>I Miei Eventi</h2>
    <a href="{% url 'events:event_create' %}" class="btn">+ Crea Nuovo Evento</a>
</div>

{% if events %}
    {% for event in events %}
        <div class="event-card">
            <div style="display: flex; justify-content: space-between; align-items: start;">
                <div style="flex: 1;">
                    <h3 class="event-title">{{ event.title }}</h3>
                    <div class="event-meta">
                        <strong> Luogo:</strong> {{ event.location }}<br>
                        <strong> Data:</strong> {{ event.start_date|date:"d/m/Y H:i" }} - {{ event.end_date|date:"H:i" }}<br>
                        <strong> Iscritti:</strong> {{ event.get_confirmed_attendees_count }}{% if event.max_attendees %} / {{ event.max_attendees }}{% endif %}<br>
                        <strong>Stato:</strong>
                        <span style="padding: 0.25rem 0.5rem; border-radius: 4px; font-size: 0.9rem;
                            {% if event.status == 'published' %}background-color: #d4edda; color: #155724;
                            {% elif event.status == 'draft' %}background-color: #fff3cd; color: #856404;
                            {% elif event.status == 'cancelled' %}background-color: #f8d7da; color: #721c24;
                            {% elif event.status == 'completed' %}background-color: #d1ecf1; color: #0c5460;
                            {% endif %}">
                            {{ event.get_status_display }}
                        </span>
                        {% if event.deleted_at %}
                            <span style="padding: 0.25rem 0.5rem; border-radius: 4px; font-size: 0.9rem; background-color: #f8d7da; color: #721c24; margin-left: 0.5rem;">
                                Eliminato
                            </span>
                        {% endif %}
                    </div>
                    <p class="event-description">{{ event.description|truncatewords:30 }}</p>
                </div>
                <div style="display: flex; flex-direction: column; gap: 0.5rem; margin-left: 1rem;">
                    <a href="{% url 'events:event_detail' event.pk %}" class="btn" style="white-space: nowrap;">Dettagli</a>
                    {% if not event.deleted_at %}
                        <a href="{% url 'events:event_update' event.pk %}" class="btn btn-secondary" style="white-space: nowrap;">Modifica</a>
                        <a href="{% url 'events:event_delete' event.pk %}" class="btn btn-danger" style="white-space: nowrap;">Elimina</a>
                    {% elif event.can_restore %}
                        <a href="{% url 'events:event_restore' event.pk %}" class="btn btn-success" style="white-space: nowrap;">Ripristina</a>
                    {% endif %}
                </div>
            </div>
        </div>
    {% endfor %}
{% else %}
    <div style="text-align: center; padding: 3rem; background-color: #f9f9f9; border-radius: 4px; margin-top: 2rem;">
        <p style="color: #666; font-size: 1.1rem;">Non hai creato nessun evento ancora.</p>
        <a href="{% url 'events:event_create' %}" class="btn" style="margin-top: 1rem;">Crea il Tuo Primo Evento</a>
    </div>
{% endif %}

<div style="margin-top: 2rem;">
    <a href="{% url 'events:event_list' %}" class="btn btn-secondary">← Torna agli Eventi</a>
</div>
{% endblock %}

{% extends 'base.html' %}

{% block title %}I Miei Eventi - Event Management System{% endblock %}

{% block content %}
<div style="display: flex; justify-content: space-between; align-items: center; margin-bottom: 2rem;">
    <h2>{% if is_admin %}Tutti gli Eventi{% else %}I Miei Eventi{% endif %}</h2>
    <a href="{% url 'events:event_create' %}" class="btn">+ Crea Nuovo Evento</a>
</div>

{% if events %}
