                            {% if event.status == 'published' %}background-color: #d4edda; color: #155724;
                            {% elif event.status == 'draft' %}background-color: #fff3cd; color: #856404;
                            {% elif event.status == 'cancelled' %}background-color: #f8d7da; color: #721c24;
                            {% elif event.status == 'completed' %}background-color: #d1ecf1; color: #0c5460;
                            {% endif %}">
