                        {% endif %}
                    </div>
                    <p class="event-description">{{ event.description|truncatewords:30 }}</p>
                </div>
                <div style="display: flex; flex-direction: column; gap: 0.5rem; margin-left: 1rem;">
                    <a href="{% url 'events:event_detail' event.pk %}" class="btn" style="white-space: nowrap;">Dettagli</a>
                    {% if not event.deleted_at %}
                        <a href="{% url 'events:event_update' event.pk %}" class="btn btn-secondary" style="white-space: nowrap;">Modifica</a>
                        <a href="{% url 'events:event_delete' event.pk %}" class="btn btn-danger" style="white-space: nowrap;">Elimina</a>
                    {% elif event.can_restore %}
                        <a href="{% url 'events:event_restore' event.pk %}" class="btn btn-success" style="white-space: nowrap;">Ripristina</a>
                    {% endif %}
                </div>
            </div>
        </div>
    {% endfor %}
{% else %}
    <div style="text-align: center; padding: 3rem; background-color: #f9f9f9; border-radius: 4px; margin-top: 2rem;">
        <p style="color: #666; font-size: 1.1rem;">Non hai creato nessun evento ancora.</p>
        <a href="{% url 'events:event_create' %}" class="btn" style="margin-top: 1rem;">Crea il Tuo Primo Evento</a>
    </div>
{% endif %}

<div style="margin-top: 2rem;">
    <a href="{% url 'events:event_list' %}" class="btn btn-secondary">← Torna agli Eventi</a>
</div>
{% endblock %}
